import { DatePipe, formatDate, formatNumber } from "@angular/common";
import { HttpClient } from "@angular/common/http";
import { Component, OnInit } from "@angular/core";
import { FormBuilder, FormGroup } from "@angular/forms";
import { Preferences } from "@capacitor/preferences";
import { AlertService } from "src/app/core/services/alert.service";
import { EnvService } from "src/app/core/services/env.service";
import { LoanApplicationsService } from "src/app/core/services/loan-applications.service";
import { LoansService } from "src/app/core/services/loans.service";
import { UserService } from "src/app/core/services/user.service";
import { DatepickerOptions } from "src/app/views/components/ngx-datepicker/datepicker.component";
import {
  Installments,
  LoanUnDisbursement,
} from "src/app/views/Models/Loan/LoanInfo";
import { LoanRejection } from "src/app/views/Models/Loan/LoanRejection";
import { LoanRejectionParent } from "src/app/views/Models/Loan/Rejection";
import { UserBranchInfo } from "src/app/views/Models/Users/User";
interface Loan {
  loanInfo: LoanUnDisbursement | undefined;
  loanInstallments: Installments[] | undefined;
}
interface LoanRejectionData {
  loanRejection: LoanRejection[] | undefined;
  loanRejectionParent: LoanRejectionParent[] | undefined;
}
@Component({
  selector: "app-loan-undisbursement",
  templateUrl: "./loan-undisbursement.page.html",
  styleUrls: ["./loan-undisbursement.page.scss"],
})
export class LoanUndisbursementPage implements OnInit {
  showLoader: boolean = false;
  isSearching: boolean = true;
  loanObject: Loan = { loanInfo: null, loanInstallments: [] };
  loanRejectionObject: LoanRejectionData = {
    loanRejection: [],
    loanRejectionParent: [],
  };
  UndisbDatePickerOptions: DatepickerOptions;
  UndisbDateDisabled: boolean = false;
  userBranchInfo: UserBranchInfo;
  periodStartDate: Date;
  periodEndDate: Date;
  constructor(
    private formBuilder: FormBuilder,
    private alertService: AlertService,
    private loansService: LoansService,
    private loanApplicationService: LoanApplicationsService,
    private userService: UserService,
    private datePipe: DatePipe
  ) {}

  loanUnDisbursmentForm: FormGroup = this.formBuilder.group({
    loanKey: [],
    clientCode: [],
    clientName: [],
    clientNationalID: [],
    clientMobile: [],
    clientAddress: [],
    coName: [],
    coNationalID: [],
    coMobile: [],
    co2Name: [],
    co2NationalID: [],
    co2Mobile: [],
    loanAmount: [],
    loanNo: [],
    loanGp: [],
    periodLength: [],
    refDesc: [],
    bankName: [],
    OfficerName: [],
    loanDate: [],
    loanVouch: [],
    uuc: [],
    loanUndisbParentReasonCode: [],
    loanUndisbChildReasonCode: [],
    disbCoName: [],
    loanNotes: [],
    undisbDate: [formatDate(new Date(), "yyyy-MM-dd", "en-ZA")],
  });
  async ngOnInit() {
    this.periodStartDate = new Date(
      (await Preferences.get({ key: "periodStartDate" })).value
    );
    this.periodEndDate = new Date(
      (await Preferences.get({ key: "periodEndDate" })).value
    );

    if (
      !localStorage.getItem("periodStartDate") ||
      !localStorage.getItem("periodEndDate")
    ) {
      this.userBranchInfo = await this.userService.getUserBranchInfo();
      if (this.userBranchInfo) {
        this.periodStartDate = new Date(this.userBranchInfo.period_start_date);
        this.periodEndDate = new Date(this.userBranchInfo.period_end_date);
        await Preferences.set({
          key: "periodStartDate",
          value: this.datePipe.transform(
            this.userBranchInfo.period_start_date,
            "yyyy-MM-dd"
          ),
        });
        await Preferences.set({
          key: "periodEndDate",
          value: this.datePipe.transform(
            this.userBranchInfo.period_end_date,
            "yyyy-MM-dd"
          ),
        });
      }
    }
    if (this.periodStartDate.toString() === this.periodEndDate.toString()) {
      this.UndisbDateDisabled = true;
    }
    if (this.loanUnDisbursmentForm.value.undisbDate > this.periodEndDate) {
      this.loanUnDisbursmentForm.patchValue({
        undisbDate: formatDate(this.periodEndDate, "yyyy-MM-dd", "en-ZA"),
      });
    }
    this.UndisbDatePickerOptions = {
      minDate: this.periodStartDate,
      maxDate: this.periodEndDate,
    };
  }

  clientSelected(event) {
    this.getLoanToUnDisbursement(event.loan_key);
  }
  async getLoanToUnDisbursement(loanKey: number) {
    try {
      this.showLoader = true;
      //Get Loan Info
      this.loanObject.loanInfo =
        await this.loansService.getLoanUnDisbursementInfo(loanKey.toString());
      //Get Installments
      this.loanObject.loanInstallments =
        await this.loansService.getInstallments(loanKey.toString());
      this.patchValueForLoanInfo();
      // Get rejection reasons (parent)
      this.loanRejectionObject.loanRejectionParent =
        await this.loanApplicationService.getRejectionRefParent();
      this.isSearching = false;
      this.showLoader = false;
    } catch (error) {
      this.showLoader = false;
      return this.alertService.showAlertError(error?.error, false);
    }
  }
  patchValueForLoanInfo() {
    this.loanUnDisbursmentForm.patchValue({
      clientCode: this.loanObject.loanInfo.client_code,
      clientName: this.loanObject.loanInfo.client_name,
      clientNationalID: this.loanObject.loanInfo.nation_id,
      clientMobile: this.loanObject.loanInfo.mobile_1,
      clientAddress: this.loanObject.loanInfo.home_add_1,
      coName: this.loanObject.loanInfo.co_name,
      coNationalID: this.loanObject.loanInfo.co_nation_id,
      coMobile: this.loanObject.loanInfo.co_mobile_1,
      co2Name: this.loanObject.loanInfo.co2_name,
      co2NationalID: this.loanObject.loanInfo.co2_nation_id,
      co2Mobile: this.loanObject.loanInfo.co2_mobile_1,
      loanAmount: formatNumber(
        Number(this.loanObject.loanInfo.loan_am),
        "en-US",
        "1.0-0"
      ),
      loanNo: this.loanObject.loanInfo.loan_no,
      loanGp: this.loanObject.loanInfo.loan_gp,
      periodLength: this.loanObject.loanInfo.period_length,
      refDesc: this.loanObject.loanInfo.ref_desc,
      bankName: this.loanObject.loanInfo.bank_name,
      OfficerName: this.loanObject.loanInfo.officer_name,
      loanDate: formatDate(
        this.loanObject.loanInfo.loan_date,
        "yyyy-MM-dd",
        "en-ZA"
      ),
      loanVouch: this.loanObject.loanInfo.loan_vouch,
      uuc: this.loanObject.loanInfo.uuc,
      loanKey: this.loanObject.loanInfo.loan_key,
      disbCoName: this.loanObject.loanInfo.disb_co_name,
      loanNotes: this.loanObject.loanInfo.loan_notes,
    });
  }
  backButton() {
    this.isSearching = true;
    this.loanUnDisbursmentForm.reset();
    this.loanObject.loanInfo = null;
    this.loanObject.loanInstallments = [];
  }
  async SubmitUnDisbursement() {
    try {
      if (!(await this.alertService.SaveAlert())) return;
      this.showLoader = true;
      await this.loansService.LoanUnDisbursement(
        this.loanUnDisbursmentForm.value.loanKey,
        this.loanUnDisbursmentForm.value.loanUndisbChildReasonCode,
        this.loanUnDisbursmentForm.value.uuc,
        this.loanUnDisbursmentForm.value.loanNotes,
        this.loanUnDisbursmentForm.value.undisbDate
      );
      this.showLoader = false;
      this.alertService.showAlertConfirm("لقد تم إلغاء الإصدار", true);
    } catch (error) {
      this.showLoader = false;
      return this.alertService.showAlertError(error?.error, false);
    }
  }
  async onParentRejChanged($event) {
    this.loanRejectionObject.loanRejection =
      await this.loanApplicationService.getLoanRejection(
        $event.detail.value.toString()
      );
  }
}
